const DOMAIN2_QUESTIONS = [
  { domain: 2, task: "2.1", q: "A company runs an application on Amazon EC2. Who is responsible for patching the guest operating system?", opts: ["AWS", "The customer", "AWS and the customer jointly", "The OS vendor"], ans: 1, explain: "With EC2, the customer is responsible for patching and maintaining the guest operating system." },
  { domain: 2, task: "2.1", q: "A team moves a database from EC2 to RDS and wants to know who handles engine updates. Who is responsible?", opts: ["The customer", "AWS", "A third-party vendor", "The database community"], ans: 1, explain: "With managed services like RDS, AWS handles database engine patching as part of the managed service." },
  { domain: 2, task: "2.1", q: "A team self-manages PostgreSQL on EC2 and needs a backup plan and restore tests. Who owns that work?", opts: ["AWS", "The customer", "AWS Support", "The database vendor"], ans: 1, explain: "When a database runs on EC2, the customer is responsible for database administration, including backups and restore testing." },
  { domain: 2, task: "2.1", q: "A company is evaluating whether to use EC2 or RDS for a MySQL database. How does the Shared Responsibility Model differ between these options?", opts: ["Both place the same responsibilities on the customer", "RDS shifts OS and database patching to AWS", "EC2 shifts more responsibility to AWS", "RDS requires the customer to manage the hardware"], ans: 1, explain: "RDS is a managed service, so AWS handles OS and database engine patching, unlike self-managed EC2." },
  { domain: 2, task: "2.1", q: "A team runs some workloads on Amazon EC2 and others on managed services like Amazon RDS. Which task is shared between AWS and the customer because each party patches different layers?", opts: ["Physical facility access", "Patch management", "Edge location security", "Hardware disposal"], ans: 1, explain: "Patch management is shared because AWS patches the managed infrastructure layers, while customers patch the guest operating system and applications they manage." },
  { domain: 2, task: "2.1", q: "A company uses Amazon ECS with AWS Fargate. Compared to ECS on EC2, which responsibility shifts to AWS?", opts: ["Application container image security", "Task definition configuration", "Host OS and infrastructure management", "IAM task role configuration"], ans: 2, explain: "With Fargate, AWS manages the underlying host OS and infrastructure, unlike ECS on EC2." },
  { domain: 2, task: "2.1", q: "A company runs a containerized application on Amazon EKS with self-managed worker nodes. Who patches the worker node operating systems?", opts: ["AWS", "The customer", "Amazon EKS automatically", "The container runtime"], ans: 1, explain: "With self-managed EKS worker nodes, the customer is responsible for OS patches on those nodes." },
  { domain: 2, task: "2.1", q: "A company stores sensitive data in Amazon S3 and wants to restrict decrypt access by using customer-managed AWS KMS keys. Under the Shared Responsibility Model, who is responsible for that configuration?", opts: ["AWS, because Amazon S3 now encrypts new objects by default", "The customer, because key choice and access control are customer responsibilities", "The compliance team at AWS", "No one, because Amazon S3 does not support KMS-based encryption"], ans: 1, explain: "Amazon S3 automatically encrypts new objects with SSE-S3 by default, but customers are still responsible for choosing stronger controls such as SSE-KMS, selecting customer-managed keys, and defining who can use them." },
  { domain: 2, task: "2.1", q: "A company uses Amazon Aurora. Which of the following is the customer's responsibility?", opts: ["Patching the Aurora database engine", "Managing the underlying EC2 instances", "Configuring database user permissions", "Maintaining storage hardware"], ans: 2, explain: "Aurora is a managed service, so AWS handles engine patching and infrastructure. The customer manages database user permissions." },
  { domain: 2, task: "2.1", q: "A team uses a managed AWS service but still needs to define how it behaves for their workload. Who configures that service?", opts: ["AWS configures all settings automatically", "The customer is responsible for configuration", "Configuration is handled by AWS Support", "Configuration is not required for managed services"], ans: 1, explain: "Managed services reduce infrastructure work, but the customer still configures the service to fit their requirements." },
  { domain: 2, task: "2.1", q: "A company wants to understand who is responsible for what when using AWS. Which document should they review?", opts: ["AWS Service Level Agreement", "AWS Shared Responsibility Model documentation", "AWS Acceptable Use Policy", "AWS Customer Agreement only"], ans: 1, explain: "The AWS Shared Responsibility Model documentation clearly delineates AWS and customer responsibilities." },
  { domain: 2, task: "2.1", q: "A company uses AWS Elastic Beanstalk. Who is responsible for the application code deployed to the platform?", opts: ["AWS", "The customer", "Elastic Beanstalk manages code automatically", "AWS manages the code when auto scaling occurs"], ans: 1, explain: "Regardless of the deployment platform, the customer is always responsible for their application code." },
  { domain: 2, task: "2.1", q: "A company wants to run a highly regulated workload. Under the Shared Responsibility Model, who is responsible for meeting regulatory compliance requirements for the data?", opts: ["AWS handles all compliance", "The customer is responsible for compliance of their data and configurations", "Compliance is automatically met when using AWS", "The regulatory body handles compliance"], ans: 1, explain: "While AWS maintains compliance certifications for infrastructure, the customer must ensure their data and configurations meet regulatory requirements." },
  { domain: 2, task: "2.1", q: "A company runs Windows Server on Amazon EC2. Who is responsible for Windows licensing compliance?", opts: ["AWS", "The customer", "Microsoft", "Licensing is included with EC2 automatically"], ans: 1, explain: "The customer is responsible for ensuring software licensing compliance on their EC2 instances, though AWS offers license-included AMIs." },
  { domain: 2, task: "2.1", q: "A company uses Amazon EFS. Which of the following is the customer's responsibility?", opts: ["File system hardware maintenance", "Physical storage management", "Configuring access points and mount targets", "Data replication across AZs"], ans: 2, explain: "EFS is managed, so AWS handles hardware and replication, but customers configure access points and mount targets." },
  { domain: 2, task: "2.1", q: "A startup uses only serverless services (Lambda, DynamoDB, API Gateway). What infrastructure responsibility remains with the customer?", opts: ["Server provisioning", "Operating system maintenance", "Capacity planning for servers", "IAM roles and permissions configuration"], ans: 3, explain: "Even with fully serverless architectures, customers are responsible for IAM configuration and access management." },
  { domain: 2, task: "2.1", q: "A company runs an application on EC2 and the underlying physical server fails. Who is responsible for migrating the instance to healthy hardware?", opts: ["The customer must manually migrate", "AWS automatically migrates to healthy hardware", "The customer must purchase a new instance", "Neither; the instance is permanently lost"], ans: 1, explain: "AWS is responsible for the infrastructure and will migrate affected instances when physical hardware fails." },
  { domain: 2, task: "2.2", q: "A team needs a service to create and manage encryption keys for application data. Which AWS service should they use?", opts: ["AWS Key Management Service (AWS KMS)", "AWS CloudTrail", "IAM access keys", "Amazon EC2 key pairs"], ans: 0, explain: "AWS Key Management Service (AWS KMS) lets you create and manage cryptographic keys for data encryption." },
  { domain: 2, task: "2.2", q: "A company needs to demonstrate PCI DSS compliance. Which AWS service provides the relevant compliance report?", opts: ["AWS Artifact", "Amazon Macie", "AWS Shield", "AWS Security Hub"], ans: 0, explain: "AWS Artifact provides access to PCI DSS compliance reports and other audit artifacts." },
  { domain: 2, task: "2.2", q: "A company needs to monitor whether any S3 buckets are publicly accessible. Which service can help?", opts: ["AWS CloudTrail", "AWS Config", "Amazon CloudFront", "AWS Direct Connect"], ans: 1, explain: "AWS Config can evaluate S3 bucket configurations against rules that check for public access." },
  { domain: 2, task: "2.2", q: "A company needs to ensure that all EBS volumes are encrypted. Which service can enforce this policy?", opts: ["AWS CloudTrail", "AWS Config", "Amazon Inspector", "AWS Artifact"], ans: 1, explain: "AWS Config rules can evaluate whether EBS volumes are encrypted and flag non-compliant resources." },
  { domain: 2, task: "2.2", q: "A team wants GuardDuty to detect suspicious network and DNS activity. Which data sources does it analyze? (Choose 2)", opts: ["S3 bucket policies", "VPC Flow Logs", "IAM password policies", "DNS query logs", "EC2 instance metrics"], ans: [1, 3], multi: true, explain: "GuardDuty analyzes VPC Flow Logs, DNS logs, and CloudTrail event logs to detect threats." },
  { domain: 2, task: "2.2", q: "A company wants to set up alerts for unusual login attempts to the AWS Management Console. Which service should they use?", opts: ["AWS Config", "Amazon GuardDuty", "AWS Artifact", "Amazon Macie"], ans: 1, explain: "GuardDuty can detect unusual API calls and console login attempts that may indicate compromised credentials." },
  { domain: 2, task: "2.2", q: "A team wants a central place to collect application and service logs for troubleshooting. Which AWS service fits best?", opts: ["AWS CloudTrail", "Amazon CloudWatch Logs", "AWS Key Management Service (AWS KMS)", "Amazon Inspector"], ans: 1, explain: "Amazon CloudWatch Logs collects, stores, and monitors log data from AWS services, applications, and on-premises resources." },
  { domain: 2, task: "2.2", q: "A company wants to detect if someone is cryptocurrency mining on their EC2 instances. Which service helps?", opts: ["Amazon Inspector", "Amazon GuardDuty", "AWS Config", "Amazon Macie"], ans: 1, explain: "GuardDuty can detect cryptocurrency mining activity through its threat intelligence and anomaly detection." },
  { domain: 2, task: "2.2", q: "A company needs to encrypt data at rest in Amazon RDS. What should they use?", opts: ["AWS CloudTrail", "AWS KMS with RDS encryption", "AWS WAF", "Amazon GuardDuty"], ans: 1, explain: "RDS integrates with AWS KMS to provide encryption at rest for database instances and snapshots." },
  { domain: 2, task: "2.2", q: "A company wants to verify that AWS infrastructure meets ISO 27001 standards. Where can they find this information?", opts: ["AWS Trusted Advisor", "AWS Artifact", "AWS Config", "AWS Security Hub"], ans: 1, explain: "AWS Artifact provides access to ISO 27001 and other compliance certifications and reports." },
  { domain: 2, task: "2.2", q: "A company needs to monitor and alert on real-time metrics for their AWS resources. Which service should they use?", opts: ["AWS CloudTrail", "Amazon CloudWatch", "AWS Config", "AWS Artifact"], ans: 1, explain: "Amazon CloudWatch monitors real-time metrics and can trigger alarms for AWS resources." },
  { domain: 2, task: "2.2", q: "A company wants to check their AWS environment against CIS Benchmarks. Which service automates this?", opts: ["AWS Artifact", "AWS Security Hub", "AWS CloudTrail", "Amazon Inspector"], ans: 1, explain: "AWS Security Hub supports automated compliance checks against CIS AWS Foundations Benchmark." },
  { domain: 2, task: "2.2", q: "A company needs to sign a HIPAA Business Associate Addendum with AWS. Where do they do this?", opts: ["AWS Support Center", "AWS Artifact Agreements", "AWS Config", "AWS Security Hub"], ans: 1, explain: "AWS Artifact Agreements allows customers to review and accept agreements like the HIPAA BAA." },
  { domain: 2, task: "2.3", q: "A company wants to grant an AWS Lambda function access to read from an S3 bucket. What should they use?", opts: ["IAM user credentials embedded in the function", "An IAM execution role attached to the Lambda function", "The root user's access keys", "An S3 access point with no authentication"], ans: 1, explain: "Lambda functions should use IAM execution roles to securely access AWS resources like S3." },
  { domain: 2, task: "2.3", q: "A company uses Active Directory on-premises. They want employees to access AWS without creating IAM users. What should they use?", opts: ["IAM groups", "Identity federation with SAML 2.0", "IAM access keys for each employee", "AWS Direct Connect"], ans: 1, explain: "SAML 2.0 federation allows on-premises Active Directory users to access AWS without needing individual IAM users." },
  { domain: 2, task: "2.3", q: "A company wants to prevent IAM users from launching EC2 instances in any Region other than us-east-1. What should they use?", opts: ["VPC endpoints", "An IAM policy with a region condition", "Security groups", "Network ACLs"], ans: 1, explain: "IAM policies can use condition keys like aws:RequestedRegion to restrict actions to specific regions." },
  { domain: 2, task: "2.3", q: "A company wants their mobile app users to access AWS resources. Which service should they use?", opts: ["IAM users for each mobile user", "Amazon Cognito", "AWS IAM Identity Center", "AWS Directory Service"], ans: 1, explain: "Amazon Cognito provides identity management for mobile and web applications, handling sign-up, sign-in, and access control." },
  { domain: 2, task: "2.3", q: "A company needs to store API keys for third-party services securely. Which AWS service should they use?", opts: ["AWS IAM", "Amazon S3", "AWS Secrets Manager", "AWS CloudFormation"], ans: 2, explain: "AWS Secrets Manager securely stores and manages secrets like API keys, with optional automatic rotation." },
  { domain: 2, task: "2.3", q: "A company needs to enforce that all IAM users use MFA to access the console. What should they configure?", opts: ["A VPC security group rule", "An IAM policy that denies access without MFA", "An S3 bucket policy", "A CloudWatch alarm"], ans: 1, explain: "An IAM policy with a condition checking aws:MultiFactorAuthPresent can deny console access without MFA." },
  { domain: 2, task: "2.4", q: "A company wants to compare third-party firewalls and security appliances that integrate with AWS. Where should they look?", opts: ["AWS Artifact", "AWS Marketplace", "AWS Config", "AWS CloudTrail"], ans: 1, explain: "AWS Marketplace offers third-party security products like firewalls, IDS/IPS, and anti-malware solutions." },
  { domain: 2, task: "2.4", q: "A company wants to block traffic from specific countries to their web application. Which service should they use?", opts: ["Security groups", "AWS WAF with geo-match conditions", "Network ACLs", "AWS Direct Connect"], ans: 1, explain: "AWS WAF supports geo-match conditions that can block or allow requests based on the country of origin." },
  { domain: 2, task: "2.4", q: "A company needs to protect their web application from cross-site scripting (XSS) attacks. Which service should they use?", opts: ["AWS Shield", "AWS WAF", "Amazon GuardDuty", "Security groups"], ans: 1, explain: "AWS WAF can create rules to detect and block XSS attacks in HTTP requests." },
  { domain: 2, task: "2.4", q: "A company wants to centrally manage security group rules, WAF rules, and Shield Advanced protections across their organization. Which service should they use?", opts: ["AWS Config", "AWS Firewall Manager", "AWS Organizations only", "AWS Security Hub"], ans: 1, explain: "AWS Firewall Manager centrally manages security group rules, WAF rules, and Shield Advanced protections across accounts." },
  { domain: 2, task: "2.4", q: "A company wants to allow HTTPS traffic on port 443 to their EC2 web servers. Where should they configure this?", opts: ["Route table", "Internet Gateway", "Security group inbound rule", "NAT Gateway"], ans: 2, explain: "Security group inbound rules should be configured to allow HTTPS traffic on port 443 to the web servers." },
  { domain: 2, task: "2.4", q: "A company wants to block IP addresses that are making more than 1000 requests per minute. Which service should they use?", opts: ["Security groups", "AWS WAF rate-based rules", "Network ACLs", "AWS Shield Standard"], ans: 1, explain: "AWS WAF rate-based rules can automatically block IP addresses that exceed a specified request threshold." },
  { domain: 2, task: "2.4", q: "A company wants to use pre-built security solutions from third-party vendors on AWS. Where should they look?", opts: ["AWS Artifact", "AWS Marketplace", "AWS Config Rules library", "AWS Security Hub"], ans: 1, explain: "AWS Marketplace offers thousands of third-party security products ready to deploy on AWS." },
  { domain: 2, task: "2.4", q: "A company wants to deny all inbound traffic to a specific subnet except for port 443. What should they use?", opts: ["Security groups only", "A Network ACL on the subnet", "An internet gateway configuration", "A route table entry"], ans: 1, explain: "A Network ACL can be configured to deny all traffic except port 443 at the subnet level." },
  { domain: 2, task: "2.4", q: "A company needs to apply AWS WAF rules consistently across 20 AWS accounts. Which service simplifies this?", opts: ["AWS Config", "AWS Firewall Manager", "AWS Organizations alone", "AWS Security Hub"], ans: 1, explain: "AWS Firewall Manager centrally manages and deploys WAF rules across multiple AWS accounts." },
  { domain: 2, task: "2.4", q: "A company needs to protect an Application Load Balancer from web application attacks. Which services should they use? (Choose 2)", opts: ["AWS WAF", "Network ACLs", "AWS Shield", "Amazon S3 Access Points", "AWS Direct Connect"], ans: [0, 2], multi: true, explain: "AWS WAF filters web requests at the ALB, and AWS Shield protects against DDoS attacks targeting the ALB." },
  { domain: 2, task: "2.2", q: "A company wants to ensure all API activity in their AWS accounts is logged. Which service should they enable?", opts: ["Amazon CloudWatch", "AWS CloudTrail", "AWS Config", "Amazon Inspector"], ans: 1, explain: "AWS CloudTrail logs all API calls across your AWS accounts for auditing and compliance." },
  { domain: 2, task: "2.3", q: "A company wants to ensure IAM users change their passwords every 90 days. What should they configure?", opts: ["IAM roles", "IAM password policy with expiration", "IAM access keys", "MFA devices"], ans: 1, explain: "IAM password policy can enforce password expiration periods, requiring users to change passwords regularly." },
  { domain: 2, task: "2.3", q: "A company uses AWS Organizations with multiple accounts. They want to restrict which AWS services can be used across all accounts. What should they use?", opts: ["IAM policies", "Service Control Policies (SCPs)", "Security groups", "Network ACLs"], ans: 1, explain: "Service Control Policies (SCPs) in AWS Organizations set permission guardrails across member accounts." },
  { domain: 2, task: "2.4", q: "A company's security team wants a single place to view all security findings from GuardDuty, Inspector, and Macie. Which service provides this?", opts: ["AWS CloudTrail", "AWS Security Hub", "Amazon CloudWatch", "AWS Config"], ans: 1, explain: "AWS Security Hub aggregates findings from GuardDuty, Inspector, Macie, and other services into a single dashboard." },
  { domain: 2, task: "2.4", q: "A company wants to subscribe to threat intelligence feeds within AWS. Which service incorporates threat intelligence automatically?", opts: ["AWS WAF", "Amazon GuardDuty", "AWS Config", "AWS Trusted Advisor"], ans: 1, explain: "Amazon GuardDuty automatically incorporates threat intelligence feeds from AWS and third-party sources for threat detection." },
  { domain: 2, task: "2.2", q: "A company wants to receive alerts when their AWS resource configurations deviate from desired settings. Which service should they use?", opts: ["AWS CloudTrail", "AWS Config Rules", "Amazon Macie", "AWS Artifact"], ans: 1, explain: "AWS Config Rules evaluate resource configurations and can trigger alerts or remediation when deviations are detected." },
  { domain: 2, task: "2.2", q: "A company needs to log all access to objects in an S3 bucket. Which feature should they enable?", opts: ["S3 versioning", "S3 server access logging or CloudTrail data events", "S3 lifecycle policies", "S3 Transfer Acceleration"], ans: 1, explain: "S3 server access logging and CloudTrail S3 data events both capture object-level access activity." },
  { domain: 2, task: "2.2", q: "A company wants to monitor for unusual billing activity that could indicate a security breach. Which service can help?", opts: ["AWS CloudTrail with CloudWatch Alarms", "Amazon Macie", "AWS Artifact", "Amazon Inspector"], ans: 0, explain: "CloudTrail logs API activity, and CloudWatch Alarms can be set to detect unusual patterns that might indicate unauthorized usage." },
  { domain: 2, task: "2.1", q: "A company is migrating from on-premises to AWS. Which of the following responsibilities are eliminated for the customer after the migration? (Select TWO)", opts: ["Managing physical server hardware", "Configuring application-level firewalls", "Maintaining data center cooling systems", "Setting up IAM roles and policies", "Encrypting data at rest"], ans: [0, 2], multi: true, explain: "Moving to AWS eliminates customer responsibility for physical server hardware and data center environmental controls like cooling. Application firewalls, IAM, and encryption remain customer responsibilities." },
  { domain: 2, task: "2.2", q: "A company wants to enforce encryption on all new EBS volumes and detect when CloudTrail logging is disabled. Which AWS services should they use together? (Select TWO)", opts: ["AWS Config rules", "Amazon GuardDuty", "AWS Service Control Policies (SCPs)", "Amazon Inspector", "AWS WAF"], ans: [0, 2], multi: true, explain: "AWS Config rules can detect non-compliant resources such as unencrypted EBS volumes. SCPs in AWS Organizations can enforce preventive controls like requiring encryption and preventing CloudTrail from being disabled." },
  { domain: 2, task: "2.3", q: "A company wants to grant third-party contractors temporary access to specific AWS resources without creating IAM users. Which of the following approaches should they use? (Select TWO)", opts: ["Cross-account IAM roles with external ID", "Sharing the root account password", "Federation with an external identity provider", "Creating permanent access keys for each contractor", "Disabling MFA for easier contractor access"], ans: [0, 2], multi: true, explain: "Cross-account roles with external IDs and identity federation both provide temporary, scoped access without creating IAM users, following security best practices." },
  { domain: 2, task: "2.4", q: "A company wants to identify EC2 instances with known software vulnerabilities and unintended network exposure. Which AWS services should they use? (Select TWO)", opts: ["Amazon Inspector", "AWS Artifact", "Amazon Detective", "AWS Systems Manager Patch Manager", "AWS CloudFormation"], ans: [0, 3], multi: true, explain: "Amazon Inspector automatically scans EC2 instances and container images for software vulnerabilities and network exposure. Systems Manager Patch Manager helps remediate those vulnerabilities by automating patching." },
  { domain: 2, task: "2.1", q: "A team uses Amazon RDS and wants to know who handles database engine updates. Who is responsible?", opts: ["The customer", "AWS", "The database vendor", "AWS Support"], ans: 1, explain: "For managed services like RDS, AWS handles database engine patching." },
  { domain: 2, task: "2.1", q: "A company wants to use AWS KMS customer-managed keys for S3 encryption instead of the default SSE-S3. Who is responsible for configuring this?", opts: ["AWS configures it automatically", "The customer", "AWS Support upon request", "Amazon S3 service team"], ans: 1, explain: "AWS enables SSE-S3 by default, but choosing stronger encryption like SSE-KMS is the customer's responsibility." },
  { domain: 2, task: "2.2", q: "A company needs to monitor for unusual activity in their AWS account, such as unexpected API calls from unfamiliar locations. Which service should they use?", opts: ["AWS WAF", "Amazon Inspector", "Amazon GuardDuty", "AWS Shield"], ans: 2, explain: "GuardDuty uses threat intelligence to detect unusual and malicious activity." },
  { domain: 2, task: "2.2", q: "A company wants to ensure all AWS resources comply with internal tagging standards. Which service evaluates resource configurations continuously?", opts: ["AWS CloudTrail", "Amazon CloudWatch", "AWS Config", "AWS Systems Manager"], ans: 2, explain: "AWS Config continuously monitors and evaluates resource configurations against rules." },
  { domain: 2, task: "2.2", q: "A company needs to track all API calls made in their AWS account for auditing purposes. Which service should they enable?", opts: ["Amazon CloudWatch", "AWS CloudTrail", "AWS Config", "AWS X-Ray"], ans: 1, explain: "CloudTrail logs all API calls and management events for auditing." },
  { domain: 2, task: "2.2", q: "A company wants to limit which AWS Regions member accounts can use within AWS Organizations. Which feature should they use?", opts: ["IAM permission boundaries", "Service Control Policies (SCPs)", "AWS Config rules", "VPC endpoint policies"], ans: 1, explain: "SCPs can restrict which Regions member accounts are allowed to operate in." },
  { domain: 2, task: "2.4", q: "A company wants to receive alerts when their AWS account root user logs in. Which combination of services should they use?", opts: ["AWS Config with SNS", "Amazon CloudWatch Events with SNS", "AWS Trusted Advisor with SES", "AWS Shield with CloudWatch"], ans: 1, explain: "CloudWatch Events can detect root user login and trigger SNS notifications." },
  { domain: 2, task: "2.4", q: "A company needs to deploy an HTTPS website behind an Application Load Balancer and wants AWS to provision and renew the certificate with no additional certificate charge. Which service should it use?", opts: ["AWS KMS", "AWS Secrets Manager", "AWS Certificate Manager", "AWS IAM"], ans: 2, explain: "AWS Certificate Manager provisions and manages SSL/TLS certificates for supported AWS services without an additional certificate charge." },
  { domain: 2, task: "2.1", q: "A company migrates their application to Amazon EC2. After the migration, they discover the operating system hasn't been patched in months. Under the Shared Responsibility Model, who is responsible for OS patching on EC2?", opts: ["AWS — they manage all infrastructure including OS patches", "The customer — they are responsible for guest OS maintenance on EC2", "AWS and the customer share OS patching responsibilities equally", "Neither — EC2 instances are automatically patched by default"], ans: 1, explain: "On EC2, the customer manages the guest OS including patching. AWS manages the underlying hypervisor and physical infrastructure. AWS does not auto-patch customer EC2 OS instances. Shared responsibility means distinct responsibilities, not equal sharing of the same task." },
  { domain: 2, task: "2.1", q: "A company uses AWS Lambda for their backend API. They want to know who is responsible for patching the runtime environment. Under the Shared Responsibility Model, who handles this?", opts: ["The customer — they must patch all compute environments they use", "AWS — they manage the underlying infrastructure and runtime for Lambda", "The customer — they must provide their own container with patches", "A third-party managed service provider contracted by AWS"], ans: 1, explain: "For managed/serverless services like Lambda, AWS handles the underlying infrastructure, OS, and runtime patching. The customer is only responsible for their function code and configuration. Customers don't provide containers or patch Lambda runtimes. AWS doesn't outsource this to third parties." },
  { domain: 2, task: "2.2", q: "A company needs to ensure all data transmitted between their on-premises data center and AWS is encrypted in transit. Which service establishes an encrypted connection?", opts: ["AWS KMS — it encrypts data at rest with managed keys", "AWS Site-to-Site VPN — it creates an encrypted tunnel over the internet", "Amazon S3 server-side encryption — it protects stored objects", "AWS Certificate Manager — it provisions SSL certificates"], ans: 1, explain: "Site-to-Site VPN creates an IPsec encrypted tunnel between on-premises and AWS VPC. KMS encrypts data at rest, not in transit. S3 SSE protects stored objects, not network traffic. ACM provisions certificates but doesn't establish the VPN connection itself." },
  { domain: 2, task: "2.3", q: "A company wants to give temporary access to a third-party auditor so they can review CloudTrail logs for 30 days, without creating a permanent IAM user. What should they use?", opts: ["Share the root account credentials with a time-limited password", "Create an IAM role with a trust policy that the auditor assumes using federation", "Create an IAM user and set a calendar reminder to delete it after 30 days", "Give the auditor an access key and revoke it manually after 30 days"], ans: 1, explain: "IAM roles with trust policies provide temporary, federated access without permanent credentials. Sharing root credentials is a critical security violation. Creating a user with manual deletion is error-prone. Access keys are long-term credentials that could be forgotten." },
  { domain: 2, task: "2.3", q: "A company has 500 employees and wants to allow them to sign in to AWS using their existing corporate Active Directory credentials. Which service enables this?", opts: ["IAM Access Analyzer to validate permissions", "AWS IAM Identity Center (SSO) with Active Directory integration", "Amazon Cognito user pools for employee sign-in", "AWS Secrets Manager to store AD credentials"], ans: 1, explain: "IAM Identity Center (formerly AWS SSO) integrates with Active Directory for federated single sign-on to AWS accounts. IAM Access Analyzer reviews permissions, not authentication. Cognito is for application end-users, not enterprise workforce SSO. Secrets Manager stores secrets but doesn't provide SSO." },
  { domain: 2, task: "2.3", q: "An organization wants to enforce that no IAM user in any of their 20 AWS accounts can disable CloudTrail logging. Which service should they use?", opts: ["AWS Config rules to detect and alert on changes", "Service Control Policies (SCPs) in AWS Organizations to deny CloudTrail actions", "IAM policies attached to each user in every account", "AWS CloudWatch alarms to notify when CloudTrail is modified"], ans: 1, explain: "SCPs in AWS Organizations set permission guardrails across all member accounts, preventing even account admins from disabling CloudTrail. Config rules detect after the fact. Individual IAM policies per user don't scale to 20 accounts. CloudWatch alarms notify but don't prevent the action." },
  { domain: 2, task: "2.2", q: "A company needs to scan their EC2 instances for unpatched CVEs and network reachability issues on a regular schedule. Which service should they use?", opts: ["Amazon GuardDuty for continuous threat monitoring", "Amazon Inspector for automated vulnerability assessments", "AWS Security Hub for aggregating security findings", "AWS Systems Manager Patch Manager for applying patches"], ans: 1, explain: "Amazon Inspector automatically scans EC2 instances (and Lambda/ECR) for software vulnerabilities and network exposure. GuardDuty detects threats from logs, not CVEs. Security Hub aggregates findings but doesn't scan. Patch Manager applies patches but doesn't assess vulnerability exposure." },
  { domain: 2, task: "2.4", q: "A company's compliance team needs to download AWS SOC 2 and ISO 27001 audit reports to satisfy their regulators. Where can they find these documents?", opts: ["AWS Trusted Advisor", "AWS Artifact", "AWS Config", "AWS Security Hub"], ans: 1, explain: "AWS Artifact provides on-demand access to AWS security and compliance documents like SOC and ISO reports. Trusted Advisor checks best practices, not compliance docs. AWS Config evaluates resource compliance. Security Hub shows compliance posture but doesn't provide downloadable audit reports." },
  { domain: 2, task: "2.2", q: "A company wants to automatically detect if any of their S3 buckets contain personally identifiable information (PII) such as Social Security numbers or credit card data. Which service should they enable?", opts: ["AWS Config with S3 bucket rules", "Amazon Macie to discover and classify sensitive data in S3", "AWS CloudTrail to log S3 access patterns", "Amazon GuardDuty S3 protection for threat detection"], ans: 1, explain: "Amazon Macie uses machine learning to automatically discover, classify, and protect sensitive data like PII in S3. Config checks bucket configuration, not content. CloudTrail logs API calls, not data content. GuardDuty S3 protection detects threats to buckets, not PII in objects." },
  { domain: 2, task: "2.2", q: "A company wants to ensure all API activity in their AWS account is recorded for forensic analysis in case of a security incident. Which service must be enabled?", opts: ["Amazon CloudWatch Logs", "AWS CloudTrail", "AWS Config", "VPC Flow Logs"], ans: 1, explain: "CloudTrail records all AWS API calls (who did what, when, from where), essential for forensic analysis. CloudWatch Logs capture application logs, not API calls. Config tracks configuration changes, not API activity. VPC Flow Logs capture network traffic metadata, not API actions." },
  { domain: 2, task: "2.4", q: "A company receives an email claiming to be from AWS Support asking them to share their account root credentials to resolve a billing issue. What should they do?", opts: ["Open a support case and provide the requested credentials", "Ignore and report the message as phishing", "Forward the message internally so someone else can respond", "Use the email link after confirming the sender domain"], ans: 1, explain: "AWS will never ask for root credentials via email, phone, or chat. This is a phishing attempt. Never share root credentials with anyone." },
  { domain: 2, task: "2.3", q: "A company manages 15 AWS accounts and wants to apply a consistent set of security baselines — including CloudTrail, GuardDuty, and Config — across all accounts automatically. Which service helps?", opts: ["AWS Organizations SCPs to restrict insecure actions", "AWS Control Tower to set up and govern a multi-account environment with guardrails", "AWS CloudFormation StackSets to deploy templates across accounts", "AWS Systems Manager to manage instances across accounts"], ans: 1, explain: "Control Tower automates multi-account setup with pre-configured guardrails including security baselines like CloudTrail and Config. SCPs restrict actions but don't auto-configure services. StackSets deploy templates but require manual guardrail design. Systems Manager manages instances, not account governance." },
  { domain: 2, task: "2.2", q: "A company wants to prevent any data from leaving their VPC over the public internet when accessing S3. Which networking feature should they configure?", opts: ["NAT Gateway", "A VPC gateway endpoint for S3", "Internet gateway", "AWS PrivateLink interface endpoint"], ans: 1, explain: "A VPC gateway endpoint for S3 routes traffic directly from the VPC to S3 without traversing the public internet. NAT Gateway and internet gateways use the public network path. PrivateLink interface endpoints are not the standard endpoint type for S3." },
  { domain: 2, task: "2.1", q: "A company uses Amazon RDS with the default configuration. After a security audit, they're told they need to manage their database network access controls. Under the Shared Responsibility Model, is this the customer's responsibility?", opts: ["No — AWS manages all networking for RDS since it's a managed service", "Yes — the customer is responsible for configuring security groups and network access for RDS", "No — RDS automatically configures optimal security group rules", "Yes — but only if the customer chose a non-default VPC"], ans: 1, explain: "Even for managed services like RDS, the customer controls network access through security groups and VPC subnet placement. AWS manages the underlying infrastructure but not customer network access decisions." },
  { domain: 2, task: "2.2", q: "A company is building a multi-account environment for regulated workloads. Security leadership wants to reduce the risk of accidental public exposure and detect configuration drift quickly. Which AWS services should the team implement first? (Select TWO)", opts: ["AWS Config with managed rules and aggregators", "AWS Security Hub", "AWS Control Tower guardrails", "AWS CloudTrail organization trails", "AWS Firewall Manager"], ans: [0, 2], multi: true, explain: "AWS Config provides continuous configuration evaluation and centralized visibility, while AWS Control Tower establishes guardrails and governance across accounts. Security Hub and CloudTrail are useful complements, but they do not replace the configuration guardrails and drift controls requested here." },
  { domain: 2, task: "2.3", q: "A company wants employees to sign in to AWS by using their corporate directory accounts and also avoid long-lived credentials for workloads running on EC2. Which approaches should the architects choose? (Select TWO)", opts: ["AWS IAM Identity Center integrated with the corporate directory", "IAM roles attached to EC2 instances", "Shared IAM users for each team", "Root account access with MFA for developers", "Static access keys stored in Systems Manager Parameter Store"], ans: [0, 1], multi: true, explain: "IAM Identity Center enables workforce federation with existing identities, and IAM roles for EC2 provide temporary credentials to workloads. Shared users, root access, and static keys are not AWS best practices." },
  { domain: 2, task: "2.3", q: "A company is onboarding a third-party vendor that needs temporary read-only access to billing reports in a dedicated AWS account. The security team wants least privilege and strong controls against confused deputy risk. Which actions should they take? (Select TWO)", opts: ["Create a cross-account IAM role with a narrowly scoped policy", "Require an external ID in the role trust policy", "Use a shared IAM user for the vendor", "Add the vendor to the root account", "Make the reports public in S3"], ans: [0, 1], multi: true, explain: "A cross-account IAM role provides temporary delegated access, and an external ID helps protect against confused deputy attacks. Sharing a user, using the root account, or making reports public would weaken security." },
  { domain: 2, task: "2.2", q: "A company hosts a public application on AWS and wants to block common web exploits while also gaining enhanced protection and response support for large DDoS events. Which services should they use? (Select TWO)", opts: ["AWS WAF", "AWS Shield Advanced", "AWS Firewall Manager", "Amazon Inspector", "AWS Config"], ans: [0, 1], multi: true, explain: "AWS WAF filters application-layer attacks such as SQL injection and XSS, while AWS Shield Advanced adds enhanced DDoS protection and access to the DDoS Response Team. Firewall Manager helps administer protections centrally, Inspector scans for vulnerabilities, and Config records compliance state." },
  { domain: 2, task: "2.1", q: "A company runs workloads on both Amazon EC2 and AWS Lambda. The security team wants to clarify who is responsible for patching and who is responsible for access control. Which statements correctly reflect the AWS Shared Responsibility Model? (Select TWO)", opts: ["For EC2, the customer is responsible for patching the guest operating system", "For Lambda, AWS is responsible for managing the underlying runtime environment", "AWS defines the least-privilege IAM policies for each customer workload", "Customers configure access to their data even when they use managed services", "AWS rotates all application secrets embedded in source code"], ans: [0, 1], multi: true, explain: "Customers patch the guest OS on EC2, while AWS manages the underlying runtime environment for Lambda. Customers still control access policies and many security decisions for managed services." },
  { domain: 2, task: "2.3", q: "A company wants to improve IAM hygiene for both human users and workloads. Security leadership wants to reduce long-lived credentials and make permissions easier to audit. Which actions align with AWS best practices? (Select TWO)", opts: ["Use IAM Identity Center or federation for workforce access", "Attach IAM roles to compute services instead of embedding access keys", "Use long-lived access keys for workloads", "Share one administrator IAM user across operations", "Use root credentials for daily access"], ans: [0, 1], multi: true, explain: "Federation reduces long-lived user credentials, and IAM roles provide temporary credentials for workloads. The other options are anti-patterns." },
  { domain: 2, task: "2.1", q: "A company runs a custom application on Amazon EC2 and stores customer records in Amazon RDS. Which task remains the customer's responsibility for the EC2 layer?", opts: ["Replacing failed physical disks", "Patching the guest operating system", "Maintaining the hypervisor", "Securing the data center floor"], ans: 1, explain: "For EC2, customers manage the guest operating system, including patching. AWS manages the physical infrastructure and hypervisor." },
  { domain: 2, task: "2.1", q: "A team moves an API from self-managed EC2 instances to AWS Lambda. Which responsibility shifts to AWS after the move?", opts: ["Writing secure application code", "Configuring IAM permissions", "Managing the underlying runtime infrastructure", "Classifying application data"], ans: 2, explain: "With Lambda, AWS manages the underlying infrastructure and runtime environment. Customers still own code, IAM configuration, and data decisions." },
  { domain: 2, task: "2.1", q: "A security auditor asks who is responsible for choosing whether customer data in an S3 bucket uses SSE-KMS with a customer-managed key. What should the team answer?", opts: ["AWS, because S3 is a managed service", "The customer, because encryption choices and key policies are customer-controlled", "The AWS compliance team", "The internet service provider"], ans: 1, explain: "AWS provides encryption capabilities, but customers choose options such as SSE-KMS and define key access policies." },
  { domain: 2, task: "2.1", q: "A company uses Amazon DynamoDB for a serverless application. Which activity remains a customer responsibility?", opts: ["Replacing storage hardware", "Patching the database host operating system", "Defining IAM permissions for application access", "Replicating data across storage devices inside an Availability Zone"], ans: 2, explain: "DynamoDB is managed by AWS, but customers still define access controls and permissions for their applications." },
  { domain: 2, task: "2.1", q: "A company deploys containers on Amazon ECS with self-managed EC2 instances. Which task belongs to the customer?", opts: ["Maintaining the AWS Region network", "Patching the EC2 container host operating systems", "Replacing failed rack hardware", "Securing the physical data center"], ans: 1, explain: "When ECS runs on customer-managed EC2 instances, the customer patches and manages the container host operating systems." },
  { domain: 2, task: "2.1", q: "A team uses Amazon SQS to decouple two services. Which security responsibility remains with the customer?", opts: ["Maintaining SQS service hardware", "Configuring queue access policies", "Patching SQS servers", "Managing the SQS storage fleet"], ans: 1, explain: "AWS operates SQS, but customers configure queue policies, IAM permissions, and application access." },
  { domain: 2, task: "2.1", q: "A company uses Amazon CloudFront to deliver private content. Under the Shared Responsibility Model, which task is customer-owned?", opts: ["Maintaining edge location facilities", "Configuring signed URLs or signed cookies for access control", "Replacing failed edge servers", "Patching CloudFront service software"], ans: 1, explain: "AWS manages CloudFront infrastructure, while customers configure distribution behavior and private-content access controls." },
  { domain: 2, task: "2.1", q: "A company runs an application on Amazon EC2 in a VPC. Which security control is the customer's responsibility?", opts: ["Configuring security group rules", "Maintaining Availability Zone power", "Patching the AWS hypervisor", "Securing physical access to racks"], ans: 0, explain: "Security groups are customer-managed network controls. AWS manages the physical and virtualization layers." },
  { domain: 2, task: "2.2", q: "A company needs a record of who changed an IAM policy, from which IP address, and at what time. Which service should they use?", opts: ["AWS CloudTrail", "Amazon CloudWatch metrics", "AWS Config only", "Amazon Macie"], ans: 0, explain: "CloudTrail records AWS API activity, including IAM policy changes, source IP address, actor, and time." },
  { domain: 2, task: "2.2", q: "A security team wants to be alerted when an S3 bucket becomes publicly readable. Which service should continuously evaluate this configuration?", opts: ["AWS Config", "AWS Artifact", "Amazon CloudFront", "AWS Shield Standard"], ans: 0, explain: "AWS Config evaluates resource configurations against rules and can detect noncompliant public S3 bucket settings." },
  { domain: 2, task: "2.2", q: "A company wants to aggregate GuardDuty, Inspector, and AWS Config security findings into a single security dashboard. Which service should they use?", opts: ["AWS Security Hub", "AWS CloudTrail", "Amazon CloudWatch Logs", "AWS Artifact"], ans: 0, explain: "Security Hub aggregates and prioritizes findings from AWS security services and supported partner tools." },
  { domain: 2, task: "2.2", q: "A regulated workload must prove that EBS volumes remain encrypted. Which AWS service can evaluate the resource configuration against a rule?", opts: ["AWS Config", "AWS CloudTrail", "AWS Certificate Manager", "AWS WAF"], ans: 0, explain: "AWS Config can evaluate whether EBS volumes comply with encryption requirements." },
  { domain: 2, task: "2.2", q: "A company needs to detect anomalous API calls and possible credential compromise across AWS accounts. Which service is most appropriate?", opts: ["Amazon GuardDuty", "AWS Artifact", "Amazon Macie", "AWS Certificate Manager"], ans: 0, explain: "GuardDuty analyzes CloudTrail events, DNS logs, and network telemetry to detect threats such as credential compromise." },
  { domain: 2, task: "2.2", q: "A team stores payment data in Amazon S3 and wants to discover objects that may contain credit card numbers. Which service should they enable?", opts: ["Amazon Macie", "AWS CloudTrail", "AWS Shield Advanced", "AWS WAF"], ans: 0, explain: "Macie discovers and classifies sensitive data such as payment card data stored in S3." },
  { domain: 2, task: "2.2", q: "A company needs to encrypt secrets used by an application and rotate database credentials automatically. Which service should it use?", opts: ["AWS Secrets Manager", "AWS Config", "Amazon GuardDuty", "AWS CloudTrail"], ans: 0, explain: "Secrets Manager stores secrets and supports automatic rotation for supported credentials." },
  { domain: 2, task: "2.2", q: "A company wants to use a managed key service to control who can decrypt S3 objects encrypted with SSE-KMS. Which service provides the keys and key policies?", opts: ["AWS Key Management Service (AWS KMS)", "AWS CloudTrail", "AWS Artifact", "Amazon Inspector"], ans: 0, explain: "AWS KMS provides managed keys and key policies used by services such as Amazon S3 for SSE-KMS encryption." },
  { domain: 2, task: "2.2", q: "A company wants to collect operating system logs and application logs from EC2 instances for security investigations. Which service should receive the logs?", opts: ["Amazon CloudWatch Logs", "AWS Artifact", "AWS WAF", "Amazon Route 53"], ans: 0, explain: "CloudWatch Logs can centralize operating system and application logs for monitoring and investigation." },
  { domain: 2, task: "2.2", q: "A company wants to know whether configuration changes caused a security incident involving a security group. Which service keeps a history of resource configuration changes?", opts: ["AWS Config", "AWS CloudTrail", "Amazon Inspector", "AWS Shield"], ans: 0, explain: "AWS Config records resource configuration history and relationships, which helps investigate changes over time." },
  { domain: 2, task: "2.2", q: "A security team needs vulnerability findings for Amazon EC2 instances and container images stored in Amazon ECR. Which service should they use?", opts: ["Amazon Inspector", "Amazon GuardDuty", "AWS Artifact", "AWS WAF"], ans: 0, explain: "Amazon Inspector scans supported workloads such as EC2 instances and ECR container images for vulnerabilities." },
  { domain: 2, task: "2.2", q: "A company needs a downloadable AWS SOC report for an external audit. Which AWS service provides this document?", opts: ["AWS Artifact", "AWS Security Hub", "Amazon CloudWatch", "AWS Config"], ans: 0, explain: "AWS Artifact provides on-demand access to AWS compliance reports such as SOC reports." },
  { domain: 2, task: "2.2", q: "A company wants to protect traffic between users and an Application Load Balancer by using a managed public TLS certificate. Which service should it use?", opts: ["AWS Certificate Manager", "AWS KMS", "AWS Secrets Manager", "Amazon GuardDuty"], ans: 0, explain: "AWS Certificate Manager provisions and manages public TLS certificates for integrated services such as Elastic Load Balancing." },
  { domain: 2, task: "2.2", q: "A compliance team wants to prove that a workload's security groups and S3 bucket settings comply with internal rules over time. Which services should they combine? (Select TWO)", opts: ["AWS Config", "AWS CloudTrail", "AWS Artifact", "AWS WAF", "AWS Shield"], ans: [0, 1], multi: true, explain: "AWS Config evaluates and records resource configurations, while CloudTrail records API activity that changed those resources." },
  { domain: 2, task: "2.3", q: "A company wants employees to use corporate identities to access multiple AWS accounts without creating separate IAM users. Which service should it use?", opts: ["AWS IAM Identity Center", "Amazon Cognito", "AWS Secrets Manager", "AWS Certificate Manager"], ans: 0, explain: "IAM Identity Center provides workforce single sign-on and can integrate with corporate identity sources for access to multiple AWS accounts." },
  { domain: 2, task: "2.3", q: "A developer needs an EC2 instance to read objects from one S3 bucket without storing access keys on the instance. Which approach follows AWS best practices?", opts: ["Attach an IAM role to the EC2 instance", "Store an IAM user's access key in a file on the instance", "Use the root user's access key", "Make the S3 bucket public"], ans: 0, explain: "An IAM role attached to the EC2 instance provides temporary credentials without storing long-lived access keys." },
  { domain: 2, task: "2.3", q: "A company wants to ensure a contractor can access only one project bucket for two weeks. Which IAM principle should guide the permissions?", opts: ["Least privilege", "Full administrator access", "Root user delegation", "Public access by default"], ans: 0, explain: "Least privilege grants only the permissions required for the task and no more." },
  { domain: 2, task: "2.3", q: "A team is granting a third-party SaaS provider access to an AWS account. Which control helps mitigate confused deputy risk?", opts: ["External ID in the role trust policy", "A shared root password", "A public S3 bucket policy", "A larger VPC CIDR block"], ans: 0, explain: "An external ID in a cross-account role trust policy helps protect against confused deputy attacks." },
  { domain: 2, task: "2.3", q: "A company wants to restrict administrators so they can create IAM roles only within a maximum approved permission set. Which IAM feature can set that maximum?", opts: ["Permissions boundary", "Security group", "Route table", "AWS Artifact agreement"], ans: 0, explain: "A permissions boundary defines the maximum permissions an IAM principal can receive." },
  { domain: 2, task: "2.3", q: "A company wants to require MFA before IAM users can perform sensitive actions such as deleting S3 buckets. What should they configure?", opts: ["An IAM policy condition that checks MFA", "A CloudFront distribution", "A VPC network ACL", "An AWS Artifact report"], ans: 0, explain: "IAM policy conditions can require MFA context before allowing sensitive actions." },
  { domain: 2, task: "2.3", q: "A mobile application needs users to sign in with social identity providers and receive temporary AWS credentials for limited access. Which service is the best fit?", opts: ["Amazon Cognito", "AWS IAM Identity Center", "AWS Organizations", "AWS CloudTrail"], ans: 0, explain: "Amazon Cognito supports application user sign-in with identity providers and can provide temporary AWS credentials." },
  { domain: 2, task: "2.3", q: "A company wants a central way to review whether resource policies allow unintended public or cross-account access. Which IAM feature helps?", opts: ["IAM Access Analyzer", "IAM groups", "EC2 key pairs", "AWS Shield Standard"], ans: 0, explain: "IAM Access Analyzer analyzes resource policies and helps identify unintended public or cross-account access." },
  { domain: 2, task: "2.3", q: "A workload running on AWS Lambda needs to write logs to CloudWatch Logs and read from a DynamoDB table. How should permissions be granted?", opts: ["Attach an IAM execution role with only the required permissions", "Embed an administrator access key in the function code", "Use the account root user credentials", "Disable IAM authentication"], ans: 0, explain: "Lambda functions use execution roles, and the role should include only the permissions the function requires." },
  { domain: 2, task: "2.3", q: "A company wants to give a finance group read-only access to billing data in several accounts. Which approach best supports centralized workforce access?", opts: ["IAM Identity Center permission sets assigned to the finance group", "One shared IAM user for the group", "Root account credentials stored in a vault", "Public billing reports in S3"], ans: 0, explain: "IAM Identity Center permission sets can grant group-based access across multiple AWS accounts without shared users." },
  { domain: 2, task: "2.4", q: "A public web application receives SQL injection attempts against its login form. Which AWS service can filter these application-layer requests?", opts: ["AWS WAF", "AWS Shield Standard", "AWS KMS", "AWS Artifact"], ans: 0, explain: "AWS WAF filters web requests and can help block application-layer attacks such as SQL injection." },
  { domain: 2, task: "2.4", q: "A company wants enhanced DDoS protection and access to specialized AWS response support for a critical public application. Which service should it use?", opts: ["AWS Shield Advanced", "AWS Shield Standard only", "AWS Artifact", "Amazon Macie"], ans: 0, explain: "Shield Advanced provides enhanced DDoS protection and access to the AWS DDoS Response Team for protected resources." },
  { domain: 2, task: "2.4", q: "A security team manages many accounts and wants to centrally deploy AWS WAF rules to Application Load Balancers across the organization. Which service helps administer this at scale?", opts: ["AWS Firewall Manager", "AWS Artifact", "AWS CloudTrail", "Amazon Inspector"], ans: 0, explain: "Firewall Manager helps centrally configure and manage firewall rules such as AWS WAF policies across accounts." },
  { domain: 2, task: "2.4", q: "A company suspects phishing because an email asks for AWS root credentials. What should the team do?", opts: ["Report the email and never share root credentials", "Reply with the credentials after opening a support case", "Forward the credentials to the security team by email", "Use the link if the sender logo looks correct"], ans: 0, explain: "AWS will not ask for root credentials by email. The team should report the phishing attempt and never share credentials." },
  { domain: 2, task: "2.4", q: "A company wants to use a prebuilt set of AWS WAF rules maintained by AWS to protect against common web exploits. What should it configure?", opts: ["AWS Managed Rules for AWS WAF", "Amazon Macie managed identifiers", "AWS Config conformance packs only", "AWS Artifact agreements"], ans: 0, explain: "AWS Managed Rules for AWS WAF provide prebuilt rule groups maintained by AWS for common web threats." },
  { domain: 2, task: "2.4", q: "A regulated company wants preventive account-level guardrails so member accounts cannot disable required security logging. Which AWS Organizations feature should it use?", opts: ["Service Control Policies (SCPs)", "VPC security groups", "CloudWatch dashboards", "AWS Artifact reports"], ans: 0, explain: "SCPs provide preventive permission guardrails across AWS Organizations member accounts." },
  { domain: 2, task: "2.4", q: "A company wants to restrict S3 access so application traffic from a VPC uses a private path and does not traverse the public internet. Which feature should it configure?", opts: ["VPC endpoint for Amazon S3", "Internet gateway", "NAT gateway only", "Public subnet route"], ans: 0, explain: "A VPC endpoint for Amazon S3 provides private connectivity from a VPC to S3 without requiring internet access." },
  { domain: 2, task: "2.4", q: "A company wants to deploy consistent detective guardrails across new AWS accounts as they are created. Which AWS service is designed to set up and govern a multi-account landing zone?", opts: ["AWS Control Tower", "Amazon CloudFront", "AWS KMS", "Amazon Route 53"], ans: 0, explain: "AWS Control Tower helps set up and govern a multi-account AWS environment with guardrails." },
  { domain: 2, task: "2.4", q: "A company needs to track security best-practice checks and compliance standard results from multiple AWS security services. Which service should be the central view?", opts: ["AWS Security Hub", "AWS Artifact", "AWS Certificate Manager", "AWS Direct Connect"], ans: 0, explain: "Security Hub provides a centralized view of security findings and compliance checks across AWS accounts and services." },
  { domain: 2, task: "2.4", q: "A security operations team wants to investigate how a GuardDuty finding relates to IAM roles, IP addresses, and API activity. Which service helps analyze and visualize those relationships?", opts: ["Amazon Detective", "AWS Artifact", "AWS Pricing Calculator", "Amazon CloudFront"], ans: 0, explain: "Amazon Detective helps security teams investigate findings by analyzing relationships among AWS resources, identities, and activity." },
  { domain: 2, task: "2.4", q: "A company needs AWS to provision and renew TLS certificates for an Application Load Balancer. Which service should it use?", opts: ["AWS Certificate Manager", "AWS Shield Advanced", "Amazon GuardDuty", "AWS Security Hub"], ans: 0, explain: "AWS Certificate Manager provisions and manages TLS certificates for supported AWS services such as Elastic Load Balancing." }
];
